class Solution {
    public List<Integer> maxScoreIndices(int[] nums) {
        int n = nums.length;
        int[] left = new int[n + 1];
        int[] right = new int[n + 1];
        for (int i = 0; i < n; i++) {
            left[i + 1] = left[i] + (nums[i] == 0 ? 1 : 0);
            right[n - i - 1] = right[n - i] + (nums[n - i - 1] == 1 ? 1 : 0);
        }
        int maxScore = 0;
        List<Integer> res = new ArrayList<>();
        for (int i = 0; i <= n; i++) {
            int score = left[i] + right[i];
            if (score > maxScore) {
                maxScore = score;
                res.clear();
                res.add(i);
            } else if (score == maxScore) {
                res.add(i);
            }
        }
        return res;
    }
}
